'use strict';

/**
 * PHASE 4 — AI Signature Detection
 *
 * Detects repos that were AI-generated by checking:
 * - Presence of specific files (.cursorrules, CLAUDE.md, rules.md, etc.)
 * - Keywords in README or repo description
 * - Common AI-builder signatures (bolt.new, lovable, v0.dev, replit agent, etc.)
 */

const logger = require('../utils/logger');

// Files whose presence strongly indicates AI generation
const AI_INDICATOR_FILES = [
  '.cursorrules',
  'CLAUDE.md',
  'claude.md',
  'rules.md',
  '.bolt',
  'bolt.config.json',
  '.replit',
  'replit.nix',
  '.lovable',
  'lovable.config.js',
  'v0.config.js',
  '.v0',
  'AGENTS.md',
  'cursor.rules',
  '.cursor/rules',
  'copilot-instructions.md',
  '.github/copilot-instructions.md',
];

// Keywords found in README / description / commit messages indicating AI generation
const AI_KEYWORDS = [
  'built with bolt.new',
  'generated by lovable',
  'agent-generated',
  'v0.dev',
  'replit agent',
  'cursor ai',
  'github copilot',
  'chatgpt generated',
  'ai generated',
  'ai-generated',
  'generated by ai',
  'made with bolt',
  'created with lovable',
  'lovable.dev',
  'generated by cursor',
  'windsurf ai',
  'codeium',
  'tabnine generated',
  'devin ai',
  'generated by devin',
  'stackblitz bolt',
];

// Regex for fast keyword scanning
const AI_KEYWORD_REGEX = new RegExp(
  AI_KEYWORDS.map(k => k.replace(/[.*+?^${}()|[\]\\]/g, '\\$&')).join('|'),
  'i'
);

/**
 * Check a list of repo file paths for AI indicator files
 * @param {string[]} filePaths - array of file paths in repo
 * @returns {{ isAI: boolean, matchedFiles: string[] }}
 */
function checkFilePaths(filePaths) {
  if (!Array.isArray(filePaths)) return { isAI: false, matchedFiles: [] };

  const matched = filePaths.filter(fp => {
    const lower = fp.toLowerCase().replace(/^\//, '');
    return AI_INDICATOR_FILES.some(indicator =>
      lower === indicator.toLowerCase() ||
      lower.endsWith('/' + indicator.toLowerCase())
    );
  });

  return {
    isAI: matched.length > 0,
    matchedFiles: matched
  };
}

/**
 * Check text content (README, description, commit messages) for AI keywords
 * @param {string} text
 * @returns {{ isAI: boolean, matchedKeywords: string[] }}
 */
function checkTextContent(text) {
  if (!text) return { isAI: false, matchedKeywords: [] };

  const matched = AI_KEYWORDS.filter(kw =>
    text.toLowerCase().includes(kw.toLowerCase())
  );

  return {
    isAI: matched.length > 0,
    matchedKeywords: matched
  };
}

/**
 * Full AI signature check — combines file + text signals
 * @param {object} repoMeta - { filePaths, description, readmeContent, commitMessages }
 * @returns {{ isAI: boolean, confidence: number, signals: object }}
 */
function detectAIRepo(repoMeta) {
  const signals = {};
  let score = 0;

  // File check (strong signal)
  if (repoMeta.filePaths?.length) {
    const fileResult = checkFilePaths(repoMeta.filePaths);
    if (fileResult.isAI) {
      signals.aiFiles = fileResult.matchedFiles;
      score += fileResult.matchedFiles.length * 30; // 30 pts per AI file
    }
  }

  // Description check
  if (repoMeta.description) {
    const descResult = checkTextContent(repoMeta.description);
    if (descResult.isAI) {
      signals.descriptionKeywords = descResult.matchedKeywords;
      score += 20;
    }
  }

  // README check
  if (repoMeta.readmeContent) {
    const readmeResult = checkTextContent(repoMeta.readmeContent);
    if (readmeResult.isAI) {
      signals.readmeKeywords = readmeResult.matchedKeywords;
      score += 25;
    }
  }

  // Commit message check
  if (repoMeta.commitMessages?.length) {
    for (const msg of repoMeta.commitMessages) {
      const commitResult = checkTextContent(msg);
      if (commitResult.isAI) {
        signals.commitKeywords = commitResult.matchedKeywords;
        score += 15;
        break; // one match is enough
      }
    }
  }

  const confidence = Math.min(score, 100);
  const isAI = confidence >= 20; // threshold: at least one meaningful signal

  if (isAI) {
    logger.debug(`[AIDetector] AI repo detected (confidence ${confidence}): signals=${JSON.stringify(signals)}`);
  }

  return { isAI, confidence, signals };
}

module.exports = { detectAIRepo, checkFilePaths, checkTextContent, AI_INDICATOR_FILES, AI_KEYWORDS };
